code = """import json

# Load all articles from file
file_path = locals()['var_functions.query_db:10']
with open(file_path, 'r') as f:
    all_articles = json.load(f)

# Let's examine articles with sports-related words to understand the data better
sports_terms = ['football', 'basketball', 'baseball', 'soccer', 'tennis', 'golf', 'hockey', 'cricket', 'game', 'team', 'player', 'coach', 'season', 'championship']

matching_articles = []
for article in all_articles:
    title = article.get('title', '').lower()
    for term in sports_terms:
        if term in title:
            matching_articles.append({
                'title': article.get('title'),
                'description': article.get('description'),
                'desc_length': len(article.get('description', ''))
            })
            break

print('__RESULT__:')
print(json.dumps({
    'matching_articles': matching_articles[:20],  # Show first 20
    'total_matches': len(matching_articles)
}, indent=2))"""

